#!/bin/bash# Stop hook — force la mise à jour du cerveau avant l'arrêt réel de la session.# stop_hook_active évite la boucle infinie (le hook qui se redéclenche après# que Claude ait fait la mise à jour).INPUT=$(cat)STOP_ACTIVE=$(echo "$INPUT" | jq -r '.stop_hook_active // false')if [ "$STOP_ACTIVE" = "true" ]; then  exit 0fiecho "Avant de terminer : applique le protocole 'EN FIN DE SESSION' décrit dans CLAUDE.md. Résume la session dans sessions.md, mets à jour tasks.md, et vérifie que BRAIN.md n'a pas de règles dupliquées/contradictoires. Fais-le maintenant en quelques lignes, puis termine normalement." >&2exit 2